const https = require('http');
const query = items[0].json.query || '';

const data = JSON.stringify({
  filter: {
    must: [
      {
        key: 'text',
        match: {
          text: query
        }
      }
    ]
  },
  limit: 10
});

const options = {
  hostname: '127.0.0.1',
  port: 6335,
  path: '/collections/nin_knowledge_graph/points/scroll',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Content-Length': data.length
  }
};

return new Promise((resolve) => {
  const req = https.request(options, (res) => {
    let body = '';
    res.on('data', (d) => body += d);
    res.on('end', () => {
      try {
        const result = JSON.parse(body);
        const relations = result.result.points.map(p => p.payload);
        resolve([{ json: { relations: relations } }]);
      } catch (e) {
        resolve([{ json: { error: 'Parse Error', raw: body } }]);
      }
    });
  });
  req.on('error', (e) => resolve([{ json: { error: e.message } }]));
  req.write(data);
  req.end();
});
